from openai import OpenAI
import re

client = OpenAI()

SAFE_OPERATIONS = {'print', 'len', 'range', 'list', 'dict', 'str', 'int', 'float'}

def validate_code_safety(code):
    lines = code.split('\n')
    for line in lines:
        imports = re.findall(r'import\s+(\w+)', line)
        execs = re.findall(r'exec\(|eval\(', line)
        if imports or execs:
            return False
    return True

# In tool_outputs handler
def safe_submit_tools(run):
    tool_calls = run.required_action.submit_tool_outputs.tool_calls
    safe_outputs = []
    for tool_call in tool_calls:
        if tool_call.function.name == 'code_interpreter':
            if validate_code_safety(tool_call.function.arguments):
                # Execute safely
                safe_outputs.append(tool_call)
    return safe_outputs

from pydantic import BaseModel, ValidationError
from openai import OpenAI

client = OpenAI()

class OrderFunction(BaseModel):
    product: str
    quantity: int

FUNCTION_SCHEMAS = {'create_order': OrderFunction}

def validate_and_execute(function_call):
    schema_cls = FUNCTION_SCHEMAS.get(function_call.function.name)
    if not schema_cls:
        return {'error': 'Unknown function'}

    try:
        args = json.loads(function_call.function.arguments)
        validated = schema_cls(**args)
        return validated.dict()
    except ValidationError as e:
        return {'error': f'Validation failed: {e}'}

